+"use client";
+
+/**
+ * Language Switcher Component
+ *
+ * Dropdown menu for selecting the application language.
+ * Uses next-intl for locale management.
+ */
+
+import { useLocale } from "next-intl";
+import { useRouter, usePathname } from "next/navigation";
+import { Globe } from "lucide-react";
+import {
+  DropdownMenu,
+  DropdownMenuContent,
+  DropdownMenuItem,
+  DropdownMenuTrigger,
+} from "@/components/ui/dropdown-menu";
+import { Button } from "@/components/ui/button";
+import { locales, localeNames, localeFlags, type Locale } from "@/i18n/config";
+
+export function LanguageSwitcher() {
+  const locale = useLocale();
+  const router = useRouter();
+  const pathname = usePathname();
+
+  const handleLocaleChange = (newLocale: Locale) => {
+    // Remove current locale prefix if present
+    const pathWithoutLocale = pathname.replace(/^\/[a-z]{2}(?=\/|$)/, "") || "/";
+
+    // Navigate to new locale path
+    const newPath = newLocale === "en" ? pathWithoutLocale : `/${newLocale}${pathWithoutLocale}`;
+    router.push(newPath);
+  };
+
+  return (
+    <DropdownMenu>
+      <DropdownMenuTrigger asChild>
+        <Button variant="ghost" size="sm" className="gap-2">
+          <Globe className="h-4 w-4" />
+          <span className="hidden sm:inline">{localeNames[locale as Locale]}</span>
+          <span className="sm:hidden">{localeFlags[locale as Locale]}</span>
+        </Button>
+      </DropdownMenuTrigger>
+      <DropdownMenuContent align="end">
+        {locales.map((loc) => (
+          <DropdownMenuItem
+            key={loc}
+            onClick={() => handleLocaleChange(loc)}
+            className={locale === loc ? "bg-accent" : ""}
+          >
+            <span className="mr-2">{localeFlags[loc]}</span>
+            {localeNames[loc]}
+          </DropdownMenuItem>
+        ))}
+      </DropdownMenuContent>
+    </DropdownMenu>
+  );
+}
